// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('check texts on screen', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('check texts on screen', async function() {
    // Test name: check texts on screen
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation-8-10/5 | 
    await driver.get("http://localhost:4200/user/evaluation-8-10/5");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | verifyText | css=.ant-card-body .ant-typography | 目標作成
    assert(await driver.findElement(By.css(".ant-card-body .ant-typography")).getText() == "目標作成");

    // 4 | verifyText | css=.ant-form-item:nth-child(2) .ant-form-item-no-colon | 評価期間
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(2) .ant-form-item-no-colon")).getText() == "評価期間");

    // 5 | verifyText | css=.ant-form-item:nth-child(3) .ant-form-item-no-colon | 氏名
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(3) .ant-form-item-no-colon")).getText() == "氏名");

    // 6 | verifyText | css=.ant-form-item:nth-child(4) .ant-form-item-no-colon | 部署
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(4) .ant-form-item-no-colon")).getText() == "部署");

    // 7 | verifyText | css=.ant-form-item:nth-child(5) .ant-form-item-no-colon | 等級
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(5) .ant-form-item-no-colon")).getText() == "等級");

    // 8 | verifyText | css=.ant-form-item:nth-child(6) .ant-form-item-no-colon | 評価者
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(6) .ant-form-item-no-colon")).getText() == "評価者");

    // 9 | verifyText | css=.ant-form-item:nth-child(7) .ant-form-item-no-colon | 状態
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(7) .ant-form-item-no-colon")).getText() == "状態");

    // 10 | verifyElementNotPresent | css=div:nth-child(2) > .ant-typography | 
    {
      const elements = await driver.findElements(By.css("div:nth-child(2) > .ant-typography"));
      assert(!elements.length);
    }

    // 11 | verifyElementNotPresent | css=#rc-tabs-1-tab-2 > span | 
    {
      const elements = await driver.findElements(By.css("#rc-tabs-1-tab-2 > span"));
      assert(!elements.length);
    }

    // 12 | verifyElementNotPresent | css=#rc-tabs-1-tab-3 > span | 
    {
      const elements = await driver.findElements(By.css("#rc-tabs-1-tab-3 > span"));
      assert(!elements.length);
    }

    // 13 | verifyElementPresent | css=.ant-space-item > div > .ant-btn > span:nth-child(1) | 
    // check PDF button exist
    {
      const elements = await driver.findElements(By.css(".ant-space-item > div > .ant-btn > span:nth-child(1)"));
      assert(elements.length);
    }

    // 14 | verifyElementPresent | css=.ant-col:nth-child(1) .ant-space-item:nth-child(1) span | 
    // check button 一時保存
    {
      const elements = await driver.findElements(By.css(".ant-col:nth-child(1) .ant-space-item:nth-child(1) span"));
      assert(elements.length);
    }

    // 15 | verifyElementPresent | css=.ant-space-item:nth-child(2) > .ant-btn > span | 
    // check button 提出
    {
      const elements = await driver.findElements(By.css(".ant-space-item:nth-child(2) > .ant-btn > span"));
      assert(elements.length);
    }

    // 16 | verifyElementPresent | css=#rc-tabs-1-tab-1 > span | 
    // check exist tab 部門目標
    {
      const elements = await driver.findElements(By.css("#rc-tabs-1-tab-1 > span"));
      assert(elements.length);
    }

    // 18 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(3) | 指標・水準（達成数値）
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "指標・水準（達成数値）");

    // 19 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(4) | 手段・方法 （どのように）
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(4)")).getText() == "手段・方法 （どのように）");

    // 20 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(5) | ウエイト
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(5)")).getText() == "ウエイト");

    // 21 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(6) | 難易度(本人)
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(6)")).getText() == "難易度(本人)");

    // 22 | verifyText | xpath=//span[contains(.,'追 加')] | 追 加
    assert(await driver.findElement(By.xpath("//span[contains(.,\'追 加\')]")).getText() == "追 加");

    // 24 | waitForElementPresent | xpath=//button[contains(.,'追 加')] | 30000
    await driver.wait(until.elementLocated(By.xpath("//button[contains(.,\'追 加\')]")), 30000);

    // 25 | click | xpath=//span[contains(.,'追 加')] | 
    await driver.findElement(By.xpath("//span[contains(.,\'追 加\')]")).click();

    // 26 | click | xpath=//span[contains(.,'追 加')] | 
    await driver.findElement(By.xpath("//span[contains(.,\'追 加\')]")).click();

    // 27 | click | xpath=(//button[@type='button'])[10] | 
    await driver.findElement(By.xpath("(//button[@type=\'button\'])[10]")).click();

    // 28 | mouseOver | xpath=//div[@id='rc-tabs-1-panel-1']/form/div/div/div/div/div/div/table/tbody/tr/td/button | 
    {
      const element = await driver.findElement(By.xpath("//div[@id=\'rc-tabs-1-panel-1\']/form/div/div/div/div/div/div/table/tbody/tr/td/button"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }

    // 29 | mouseOut | css=.ant-table-row-expand-icon-expanded | 
    {
      const element = await driver.findElement(By.CSS_SELECTOR, "body");
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }

    // 30 | verifyText | css=.ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(1) | 評価判断指標
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(1)")).getText() == "評価判断指標");

    // 31 | verifyText | css=.ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(2) | 係数
    assert(await driver.findElement(By.css(".ant-table-cell:nth-child(1) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(2)")).getText() == "係数");
  });
});
